sys_script.script:
var isValid = true;
var errorMessages = [];

// Validate new premium amount
var newPremium = current.getValue('new_premium');
if (!gs.nil(newPremium)) {
    var premiumNum = parseFloat(newPremium);
    if (isNaN(premiumNum) || premiumNum <= 0) {
        isValid = false;
        errorMessages.push('New premium amount must be a positive number.');
    }
}

// Validate renewal date is in the future
if (!current.renewal_date.nil()) {
    var renewalDate = new GlideDateTime(current.getValue('renewal_date'));
    var currentDate = new GlideDateTime();

    if (renewalDate.compareTo(currentDate) <= 0) {
        isValid = false;
        errorMessages.push('Renewal date must be in the future.');
    }
}

// Validate premium increase is reasonable (not more than 50% increase)
if (!current.previous_premium.nil() && !current.new_premium.nil()) {
    var oldPremium = parseFloat(current.getValue('previous_premium'));
    var newPremium = parseFloat(current.getValue('new_premium'));

    if (oldPremium > 0) {
        var increasePercent = ((newPremium - oldPremium) / oldPremium) * 100;
        if (increasePercent > 50) {
            gs.addInfoMessage('Warning: Premium increase of ' + Math.round(increasePercent) + 
                            '% detected. Please review.');
        }
    }
}

if (!isValid) {
    gs.addErrorMessage('Renewal Validation Error: ' + errorMessages.join(' '));
    current.setAbortAction(true);
}
